import{_ as a,o as t,c as i,ag as n}from"./chunks/framework.fgRodP1M.js";const u=JSON.parse('{"title":"Data Pipeline","description":"","frontmatter":{},"headers":[],"relativePath":"projects/data-pipeline.md","filePath":"projects/data-pipeline.md","lastUpdated":1777962526000}'),r={name:"projects/data-pipeline.md"};function o(l,e,s,d,c,h){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="data-pipeline" tabindex="-1">Data Pipeline <a class="header-anchor" href="#data-pipeline" aria-label="Permalink to &quot;Data Pipeline&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><strong>Data Pipeline</strong> covers an internal-style but publicly described architecture: turning robot logs into curated datasets suitable for learning and evaluation, with consent, retention, and access boundaries treated as engineering requirements—not afterthoughts.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Physical AI progress depends on data quality and lineage. If provenance is fuzzy, models inherit silent failure modes that only appear under distribution shift.</p><h2 id="technical-scope" tabindex="-1">Technical Scope <a class="header-anchor" href="#technical-scope" aria-label="Permalink to &quot;Technical Scope&quot;">​</a></h2><ul><li>Structured capture metadata: robot revision, controller version, calibration IDs</li><li>De-identification steps for environments that may include incidental background cues</li><li>Replay harnesses for regression on <strong>ROS 2</strong> bags with timing preserved</li></ul><h2 id="what-i-learned" tabindex="-1">What I Learned <a class="header-anchor" href="#what-i-learned" aria-label="Permalink to &quot;What I Learned&quot;">​</a></h2><ul><li><strong>Schema discipline early</strong> saves painful rewrites when storage costs force compaction.</li><li>Evaluation sets need “boring” negatives: near-misses and benign failures, not only success reels.</li></ul><h2 id="related-notes" tabindex="-1">Related Notes <a class="header-anchor" href="#related-notes" aria-label="Permalink to &quot;Related Notes&quot;">​</a></h2><ul><li><a href="/lifeops_blog/articles/physical-ai/">Physical AI articles</a></li><li><a href="/lifeops_blog/reading/papers.html">Reading: Papers</a></li></ul>',11)])])}const f=a(r,[["render",o]]);export{u as __pageData,f as default};
